import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { motion } from 'framer-motion';

const Quiz = () => {
  const [questions, setQuestions] = useState([]);
  const [step, setStep] = useState(0);
  const [choice, setChoice] = useState(''); // Stocke soit le clic, soit le texte tapé
  const [status, setStatus] = useState('idle');

  useEffect(() => {
    axios.get('http://localhost:8000/questions/random?limit=30')
      .then(res => setQuestions(res.data))
      .catch(err => console.error("Erreur chargement questions:", err));
  }, []);

  const q = questions[step];

  const handleCheck = () => {
    // On compare en ignorant les espaces superflus et la casse pour la saisie libre
    const isCorrect = q.choix_multiple 
      ? choice === q.solution 
      : choice.trim().toLowerCase() === q.solution.trim().toLowerCase();
    
    setStatus(isCorrect ? 'correct' : 'wrong');
  };

  const handleNext = () => {
    setChoice('');
    setStatus('idle');
    setStep(s => s + 1);
  };

  if (!questions.length) return <div className="p-10 text-center font-bold">Chargement du défi MongoDB...</div>;
  if (step >= questions.length) return <div className="text-center p-10 bg-white rounded-3xl shadow">🏁 Quiz terminé !</div>;

  return (
    <div className="flex flex-col gap-6">
      {/* Progression */}
      <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden">
        <div className="bg-green-500 h-full transition-all duration-500" style={{ width: `${(step / questions.length) * 100}%` }} />
      </div>

      <div className="bg-white p-8 rounded-3xl border-2 border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-4">
            <span className="text-xs font-black text-blue-500 uppercase tracking-widest">{q.difficulte}</span>
            <span className="text-xs font-bold text-slate-400">{q.choix_multiple ? "📱 QCM" : "💻 SYNTAXE"}</span>
        </div>
        
        <h2 className="text-2xl font-bold mb-8">{q.enonce}</h2>

        {/* --- AFFICHAGE CONDITIONNEL --- */}
        {q.choix_multiple ? (
          <div className="grid gap-3">
            {q.propositions && q.propositions.map((p, i) => (
              <button
                key={i}
                disabled={status !== 'idle'}
                onClick={() => setChoice(p)}
                className={`p-4 rounded-2xl border-2 text-left transition-all font-mono text-sm ${
                  choice === p ? 'border-blue-400 bg-blue-50' : 'border-slate-100 hover:bg-slate-50'
                } ${status !== 'idle' && p === q.solution ? 'border-green-500 bg-green-50' : ''}`}
              >
                {p}
              </button>
            ))}
          </div>
        ) : (
          <div className="flex flex-col gap-2">
            <label className="text-sm font-bold text-slate-500 ml-1">Ta réponse (requête MongoDB) :</label>
            <input
              type="text"
              value={choice}
              disabled={status !== 'idle'}
              onChange={(e) => setChoice(e.target.value)}
              placeholder="db.collection.find()..."
              className={`p-4 rounded-2xl border-2 font-mono text-sm outline-none transition-all ${
                status === 'idle' ? 'border-slate-200 focus:border-blue-400' : 
                status === 'correct' ? 'border-green-500 bg-green-50' : 'border-red-500 bg-red-50'
              }`}
            />
            {status === 'wrong' && (
              <div className="mt-2 p-3 bg-red-50 text-red-700 rounded-xl text-sm font-mono">
                La réponse attendue : {q.solution}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Barre de feedback style Duolingo */}
      <div className={`p-6 rounded-2xl flex items-center justify-between ${
        status === 'idle' ? 'bg-white border-2 border-slate-200' : status === 'correct' ? 'bg-green-100' : 'bg-red-100'
      }`}>
        <div className="flex-1">
          {status !== 'idle' && (
            <motion.div initial={{ y: 10, opacity: 0 }} animate={{ y: 0, opacity: 1 }}>
              <h3 className={`font-black text-xl ${status === 'correct' ? 'text-green-700' : 'text-red-700'}`}>
                {status === 'correct' ? 'Bien joué !' : 'Oups...'}
              </h3>
              <p className="text-slate-700 text-sm mt-1">{q.explication}</p>
            </motion.div>
          )}
        </div>
        
        {status === 'idle' ? (
          <button onClick={handleCheck} disabled={!choice} className="bg-green-500 text-white px-8 py-3 rounded-xl font-black shadow-[0_4px_0_0_#22c55e] disabled:opacity-50">
            VÉRIFIER
          </button>
        ) : (
          <button onClick={handleNext} className="bg-blue-500 text-white px-8 py-3 rounded-xl font-black shadow-[0_4px_0_0_#3b82f6]">
            CONTINUER
          </button>
        )}
      </div>
    </div>
  );
};

export default Quiz;
